def solve(points: Array[Array[Long]]): Long = {
  val n = points.length
  if (n < 4) return 0L

  val slopeCount = scala.collection.mutable.HashMap[Double, Int]()

  for (i <- 0 until n) {
    val (x1, y1) = (points(i)(0), points(i)(1))
    for (j <- i + 1 until n) {
      val (x2, y2) = (points(j)(0), points(j)(1))
      val dx = x2 - x1
      val dy = y2 - y1
      var slope: Double = 0.0
      if (dx == 0) {
        slope = Double.PositiveInfinity
      } else {
        slope = dy.toDouble / dx
      }
      slopeCount(slope) += 1
    }
  }

  var count = 0L
  for ((slope, cnt) <- slopeCount.iterator) {
    if (cnt >= 2) {
      count += (cnt * (cnt - 1)) / 2
    }
  }

  count
}
